  render: () => {
    let toastId: string | number | undefined;
    return <div style={{
      display: 'flex',
      gap: '0.5rem'
    }}>
                <Button variant="secondary" onClick={() => {
        toastId = toast.info('Uploading...', {
          duration: 60_000
        });
      }}>
                    Start
                </Button>
                <Button variant="ghost" onClick={() => {
        if (toastId !== undefined) toast.dismiss(toastId);
      }}>
                    Dismiss
                </Button>
            </div>;
  }
